def detect_hallucinated_tools(task_output: str) -> bool:
    tool_patterns = [
        r'\d{5,}',  # Unrealistic large numbers
        r'error.*code.*999',  # Fake error codes
        r'API\s+key\s+required',  # Hallucinated auth failures
    ]
    return any(re.search(pattern, task_output, re.IGNORECASE) for pattern in tool_patterns)

