from crewai import Task
class CostOptimizedTask(Task):
    def __init__(self, *args, max_delegations=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.delegation_count = 0
        self.max_delegations = max_delegations

    def should_delegate(self):
        if self.delegation_count >= self.max_delegations:
            return False
        self.delegation_count += 1
        return super().should_delegate()

def validate_tool_output(tool_result: dict) -> bool:
    required_fields = ['success', 'data', 'error']
    if not all(field in tool_result for field in required_fields):
        return False

    if tool_result['success'] and len(str(tool_result['data'])) > 5000:
        return False  # Suspiciously verbose

    return tool_result['success'] or 'timeout' not in tool_result['error']

from crewai import Agent
class CostAwareAgent(Agent):
    def __init__(self, *args, max_output_tokens=2000, **kwargs):
        super().__init__(*args, **kwargs)
        self.max_output_tokens = max_output_tokens

    def execute_task(self, task):
        result = super().execute_task(task)
        # Rough token estimation: 4 chars per token
        if len(result) > self.max_output_tokens * 4:
            result = result[:self.max_output_tokens * 4] + '... [TRUNCATED]'
        return result
